// src/pages/gov/BanksPage.jsx
import { useState, useEffect } from "react";
import { useToast }            from "../../context/ToastContext";
import PageHeader              from "../../components/shared/PageHeader";
import DataTable               from "../../components/shared/DataTable";
import { bankApi }             from "../../services/api";

const fmt   = (n) => n?.toLocaleString() ?? "–";
const short = (s) => s?.length > 12 ? s.slice(0, 12) + "…" : s;

export default function BanksPage() {
  const toast = useToast();
  const [banks,    setBanks]   = useState([]);
  const [fetching, setFetching] = useState(true);

  useEffect(() => {
    bankApi.getAll()
      .then((res) => setBanks(res.data || []))
      .catch(() => toast("Failed to load banks", "error"))
      .finally(() => setFetching(false));
  }, []);

  return (
    <div>
      <PageHeader title="All Banks" desc="Authorized financial institutions" />
      <div className="card">
        {fetching ? (
          <p style={{ color: "var(--text-muted)" }}>Loading…</p>
        ) : (
          <DataTable
            columns={[
              { key: "id",          label: "Bank ID",     mono: true },
              { key: "name",        label: "Institution" },
              { key: "country",     label: "Country" },
              { key: "address",     label: "Address",     mono: true, render: (r) => short(r.address) },
              { key: "issued",      label: "Issued",      render: (r) => <span className="text-gold">{fmt(r.issued)}</span> },
              { key: "circulating", label: "Circulating", render: (r) => fmt(r.circulating) },
            ]}
            data={banks}
          />
        )}
      </div>
    </div>
  );
}
